// // If sp is 01, then c is 0.
// If sp is 10, then c is 1.
// If sp is 11, then c is 0.
// If sp is 00, then c is 1.
module top_module (
    input s,
    input p,
    output reg c
);
    always @(*) begin
        case ({s, p})
            2'b01: c = 1'b1;
            2'b10: c = 1'b0;
            2'b11: c = 1'b1;
            2'b00: c = 1'b0;
        endcase
    end
endmodule

